// ── V2 Task Envelope: task_id propagation ─────────────────────────────────────
const _env = (typeof $input !== 'undefined' && $input.all()[0].json) || {};
const _envBody = _env.body || {};
const _inherited_task_id = _envBody.task_id || null;
const _gen_task_id = () => 'tid-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 9);
const _task_id = _inherited_task_id || _gen_task_id();
// ── End V2 Task Envelope ────────────────────────────────────────────────────────

const src = $input.all()[0];
// ── Loop prevention guard ────────────────────────────────────────────────────
const _incomingBody = (src.json && src.json.body) ? src.json.body : {};
const _attemptCount = (_incomingBody.attempt_count !== undefined)
    ? parseInt(_incomingBody.attempt_count, 10) || 0 : 0;
if (_attemptCount >= 1) {
    return [{ json: { loop_detected: true, original_task: _incomingBody,
        bot_name: 'cleaner',
        task: 'loop_escalation', user_text: null, chat_id: null, from_agent: 'loop_guard',
        now_iso: new Date().toISOString(), daily_spec: [], weekly_spec: [] } }];
}
// ── End loop prevention ──────────────────────────────────────────────────────

// ── Deduplication guard ─────────────────────────────────────────────────────
const messageId = (src.json && src.json.message && src.json.message.message_id)
    ? String(src.json.message.message_id)
    : null;


// Detect trigger source by inspecting the item shape.
let task = 'scheduled_tick';
let user_text = null;
let chat_id = null;
let from_agent = 'system';

if (src.json && src.json.message && src.json.message.chat) {
    // Telegram trigger
    task = 'user_dm';
    let _utext = src.json.message.text || '';
    // Strip leading slash from Telegram commands so Super Agent does not classify them as shell commands.
    if (_utext.startsWith('/')) {
        const parts = _utext.slice(1).split(/\s+/);
        const cmd = (parts[0] || '').toLowerCase();
        const rest = parts.slice(1).join(' ');
        if (cmd === 'start' || cmd === 'help') { _utext = 'Hello - please introduce yourself, your role in Bridge Digital, and what you can help with right now.'; }
        else if (cmd === 'status') { _utext = 'Give me a brief status update on your current focus and any open items in your inbox.'; }
        else { _utext = (cmd + ' ' + rest).trim(); }
    }
    user_text = _utext;
    chat_id = src.json.message.chat.id;
    from_agent = 'user';
} else if (src.json && src.json.body && src.json.body.task) {
    // Webhook trigger
    task = src.json.body.task;
    user_text = src.json.body.message || null;
    from_agent = src.json.body.from_agent || 'system';
    chat_id = null; // webhooks do not carry a telegram chat
} else if (src.json && src.json.timestamp) {
    // Schedule trigger
    task = 'scheduled_tick';
    user_text = null;
    from_agent = 'system';
}

return [{ json: { message_id: messageId,
    bot_name: "cleaner",
    task,
    user_text,
    chat_id,
    from_agent,
    now_iso: new Date().toISOString(),
    daily_spec: [{"hour": 22, "minute": 0, "task_name": "nightly_cleanup"}],
    weekly_spec: [{"weekday": 5, "hour": 18, "minute": 0, "task_name": "weekly_archive_cycle"}],
    task_id: _task_id,
} }];

const _buildTask = $('Build task payload').first().json;
if (_buildTask.loop_detected) {
    return [{ json: {
        message: JSON.stringify({ reply_text: '', actions: [{ type: 'no_op', payload: {
            reason: 'loop_detected', attempt_count: (_buildTask.original_task && _buildTask.original_task.attempt_count) || 1
        }}]}),
        session_id: 'bridge-loop-guard-' + Date.now(),
        task_kind: 'loop_escalation', user_chat_id: null,
        bot_name: _buildTask.bot_name || 'unknown', _pre_formed: true
    }}];
}

const task = $('Build task payload').first().json;
// ── Memory auto-block check (non-blocking) ──────────────────────────────────
let _autoBlockActive = false;
const _querySubject = task.user_text || task.subject || '';
if (_querySubject && _querySubject.length > 5) {
    try {
        const _memCheck = await $http.post(
            `${$env.SUPER_AGENT_URL || 'https://super-agent-production.up.railway.app'}/webhook/memory-query`,
            { project_name: _querySubject.slice(0, 100), api_key: $env.N8N_API_KEY || '' }
        );
        if (_memCheck && _memCheck.data && _memCheck.data.auto_block === true) {
            _autoBlockActive = true;
            return [{ json: {
                message: JSON.stringify({
                    reply_text: `🚫 AUTO-BLOCK: Project has been rejected ${_memCheck.data.rejection_count} time(s). Route to CRO then CEO for override.`,
                    actions: [{ type: 'no_op', payload: {
                        reason: 'auto_block_repeated_rejection',
                        rejection_count: _memCheck.data.rejection_count,
                        similar_projects: _memCheck.data.similar_projects
                    }}]
                }),
                session_id: `bridge-auto-block-${Date.now()}`,
                task_kind: 'auto_block', user_chat_id: task.chat_id,
                bot_name: task.bot_name, _pre_formed: true
            }}];
        }
    } catch(e) { /* non-blocking */ }
}


const inboxRow = $('Fetch open inbox').first().json || {};
const inbox = Array.isArray(inboxRow.open_inbox) ? inboxRow.open_inbox : [];
const ctxRow = $('Fetch bot context').first().json || {};
const ctx = ctxRow.context ? [ctxRow.context] : [ctxRow];


const globalProtocol = `

GLOBAL OPERATING PROTOCOL (non-negotiable):
1. ALWAYS respond in valid JSON only. No prose, no markdown outside JSON strings.
2. EXACT response structure: {"reply_text": "...", "actions": [...]}
3. reply_text: human-readable Telegram message. Brief, role-appropriate.
4. actions: array of {type, payload} objects. Empty array if no actions.
5. NEVER include PLACEHOLDER, PASTE_, TBD, INSERT_HERE values in any field.
6. NEVER mention internal tools (n8n, shell, SQL, workflow IDs) in reply_text.
7. If required data is missing → return no_op with status "need_input" + list exact missing fields.
8. If blocked → escalate to Chief of Staff. NEVER retry autonomously.
9. MAX_RETRIES = 1. If attempt_count >= 1 in incoming body_json → return no_op immediately.
`;

const system = "You are Bridge_Cleaner_bot, the enterprise maintenance, hygiene, reset, and lifecycle management super-agent inside Bridge Digital Solutions.\n\nROLE\nYou are responsible for keeping the ecosystem clean, orderly, efficient, and recoverable. You remove clutter, archive stale items, recycle temporary resources, reset expired states, and preserve operational hygiene across workflows, data, storage, environments, and temporary assets.\n\nPRIMARY OBJECTIVES\n1. Keep the enterprise free from stale, expired, duplicated, or wasteful operational residue.\n2. Recycle temporary resources efficiently.\n3. Improve system clarity, performance, and cost discipline through maintenance hygiene.\n4. Support lifecycle completion after campaigns, workflows, builds, meetings, and project stages.\n\nSECONDARY OBJECTIVES\n1. Prevent resource leakage and state confusion.\n2. Support finance and PM by reducing unnecessary operational overhead.\n3. Maintain archival discipline and closure integrity.\n\nCORE FUNCTIONS\nArchive stale records, reset expired states, recycle temporary resources, remove duplicate or abandoned artifacts, close completed maintenance loops, clean demo-site and temporary deployment residue, keep storage and workflow states organized, mark unresolved clutter for escalation, support end-of-day and end-of-week cleanup cycles.\n\nWHAT YOU MUST CLEAN OR MANAGE\nexpired demo websites, temporary deployment resources, stale queue items, abandoned drafts, duplicated temporary files, old cache-like workflow residues, inactive or expired work states, no-longer-needed artifacts after PM or finance decisions, archival routing for historical traceability.\n\nDECISION PRINCIPLES\n- Do not delete what should be archived.\n- Do not archive what is still active.\n- Prefer recoverable cleanup over destructive cleanup.\n- Respect security, legal, and finance retention rules.\n- Improve clarity, reduce waste, and preserve traceability.\n\nAUTHORITY AND AUTONOMY\nYou may archive expired or approved-for-closure assets, reset stale states according to policy, reclaim temporary resources, flag clutter and maintenance risks, request PM review for ambiguous cleanup cases.\nYou may not destroy protected data without approved policy, remove legally or financially important records, override active project ownership without escalation.\n\nINTERACTION RULES\nYou work with Bridge_Chief_Of_Staff_bot for cleanup timing and closure authority, Bridge_CEO_BOT only through escalated operational summaries when waste becomes strategic, Bridge_Chief_Sec_Off_bot for secure cleanup and retention compliance, finance and project workflows for budget-saving resource reclamation.\n\nESCALATE WHEN an item is stale but ownership is ambiguous, cleanup might affect legal/financial/security obligations, resource leakage is recurring, multiple abandoned states indicate process failure, or temporary assets are consuming unnecessary budget.\n\nOUTPUT STYLE\nAlways organize outputs as: items cleaned, items archived, items recycled, items needing approval, risks from clutter, savings or efficiency impact.\n\nNOTE FOR THIS RUNTIME\nThe CONTEXT_QUERY you receive already auto-archives stale website_projects rows older than 12 hours whose lead is not 'Interested'. Reflect this in your reply_text (count and a short list of slugs). For destructive GitHub file deletion of those archived demos, emit a 'cleanup' action with payload {slug, reason} \u2014 that goes through user approval, never auto-executes.\n\nSUCCESS DEFINITION\nYou are successful when the enterprise stays lean, orderly, cost-efficient, and free from stale operational buildup.\n\nSAFETY RULE: Before any cleanup action, set requires_approval=true in payload.\nDescribe EXACTLY what will be removed and why in reply_text.\nNever cleanup >10 records per action. Archive, do not delete, unless explicitly instructed.\n\nDATABASE VOLUME MAINTENANCE (weekly):\nResponsible for preventing postgres-volume from filling up (10GB limit).\nWeekly: delete resolved memos >30d, workflow_events >60d, agent_performance >90d, cro_evaluations >90d.\nReport cleanup stats and current DB size. Escalate to CEO if DB > 8GB.";

const contextBlock = JSON.stringify({
    now: task.now_iso,
    bot: task.bot_name,
    task_kind: task.task,
    open_inbox: inbox,
    bot_context: ctx,
    daily_cadence: task.daily_spec,
    weekly_cadence: task.weekly_spec,
}, null, 2);

const taskBlock = task.task === 'user_dm'
    ? `The user sent you this message on Telegram:\n${task.user_text}\n\nRespond helpfully and consider issuing actions if appropriate.`
    : task.task === 'scheduled_tick'
      ? `This is a scheduled cadence run. Decide what to do given the current context, open memos, and your role.`
      : `An inter-agent invocation arrived from '${task.from_agent}': ${task.user_text || 'no message body'}. Decide how to respond.`;

const outputGuard = `\n\n[OUTPUT FORMAT]\nReturn ONLY a JSON object (no prose, no markdown fences):\n{\n  "reply_text": "<what to send back via Telegram; empty string when a scheduled run should stay silent>",\n  "actions": [\n    {"type": "memo",     "payload": {"to_agent": "researcher|chief_of_staff|cso|ceo|cleaner|all", "memo_type": "status|proposal|directive|question|decision", "priority": "urgent|high|normal|low", "subject": "...", "body_json": {...}}},\n    {"type": "archive",  "payload": {"memo_id": "<uuid-from-open-inbox>", "reason": "..."}},\n    {"type": "query",    "payload": {"sql": "<safe single SELECT>"}},\n    {"type": "escalate", "payload": {"subject": "...", "body_json": {...}}},\n    {"type": "cleanup",  "payload": {"slug": "...", "reason": "..."}},\n    {"type": "no_op",    "payload": {"reason": "..."}}\n  ]\n}\nKeep actions <= 5. Never include non-whitelisted action types. User-facing commentary belongs in reply_text, not in alert actions.`;

const fullMessage = `${system}${globalProtocol}\n\n[CONTEXT]\n${contextBlock}\n\n[TASK]\n${taskBlock}${outputGuard}`;

return [{ json: {
    message: fullMessage,
    session_id: `bridge-${task.bot_name}-${task.now_iso.slice(0,16).replace(/[:T-]/g,'')}`,
    task_kind: task.task,
    user_chat_id: task.chat_id,
    bot_name: task.bot_name,
} }];

// Passthrough — bot-engine already parsed, validated, and risk-annotated the response.
const _upstream = $('Assemble prompt').first().json;
if (_upstream && _upstream._pre_formed) {
    let _pfActions;
    try { _pfActions = JSON.parse(_upstream.message).actions; } catch(e) { _pfActions = []; }
    return [{ json: {
        reply_text: '',
        actions: [{ type: 'no_op', risk: 'low',
            payload: (_pfActions[0] && _pfActions[0].payload) || { reason: 'loop_guard' } }],
        bot_name: _upstream.bot_name, user_chat_id: _upstream.user_chat_id,
        task_kind: 'loop_escalation', model_used: 'loop_guard', parse_error: null
    }}];
}
const upstream = $('Assemble prompt').first().json;
return [{ json: {
    reply_text:  $json.reply_text  || '',
    actions:     Array.isArray($json.actions) ? $json.actions : [],
    model_used:  $json.model_used  || 'unknown',
    parse_error: $json.parse_error || null,
    bot_name:    upstream.bot_name,
    user_chat_id: upstream.user_chat_id,
    task_kind:   upstream.task_kind,
} }];

const p = $json;
const out = [];
for (const a of (p.actions || [])) {
    out.push({ json: {
        action_type: a.type,
        action_risk: a.risk,
        action_payload: a.payload,
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
// Always emit at least one item so the reply path runs even when no actions.
if (out.length === 0) {
    out.push({ json: {
        action_type: 'no_op',
        action_risk: 'low',
        action_payload: { reason: 'no actions from LLM' },
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
return out;

